import React from "react";

function Services() {
  const services = [
    {
      icon: "🏗️",
      title: "Modular Infrastructure Healing",
      description: "We design and implement modular housing, water systems, and community structures that blend technical precision with spiritual resonance."
    },
    {
      icon: "🎨",
      title: "Branding & Identity",
      description: "Motif-driven logos, letterheads, and document styling for authoritative, expressive business communication."
    },
    {
      icon: "📊",
      title: "Stakeholder Presentations",
      description: "Visually rich PDFs and slide decks for government, investor, and communal review, narratable and spiritually resonant."
    },
    {
      icon: "⚙️",
      title: "CLI-First Workflow",
      description: "Reproducible, editor-free solutions for technical and branding assets, ensuring modularity and efficiency."
    },
    {
      icon: "📜",
      title: "Ceremonial Storytelling",
      description: "Scripts, cheat sheets, press releases, taglines, slogans, and pledges for visionary stakeholder engagement."
    }
  ];

  return (
    <div style={{ padding: "40px" }}>
      <h1 style={{ textAlign: "center", color: "#004080", marginBottom: "30px" }}>
        Our Services
      </h1>
      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
        gap: "20px"
      }}>
        {services.map((service, index) => (
          <div key={index} style={{
            border: "1px solid #ccc",
            borderRadius: "8px",
            padding: "20px",
            backgroundColor: "#fafafa",
            textAlign: "center"
          }}>
            <div style={{ fontSize: "40px", marginBottom: "15px" }}>{service.icon}</div>
            <h2 style={{ color: "#004080" }}>{service.title}</h2>
            <p style={{ color: "#555" }}>{service.description}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Services;
